  "executive_summary": "For a small-team courier notification system requiring high reliability, future channel extensibility, and tolerating 5-minute latency, the event-driven approach (Option B) with a managed message queue is the clear winner. It decouples delivery tracking from notification dispatch, gives retry semantics for free, and makes adding new channels a matter of deploying a new worker — not modifying the delivery service. The key is to use a managed queue (AWS SQS, Google Cloud Tasks, or similar) so the 3-engineer team avoids operating message broker infrastructure.",

  "architecture": {
    "components": [
      {
        "name": "Delivery Service",
        "responsibility": "Tracks package lifecycle (picked up, in transit, out for delivery, delivered). Publishes domain events on state transitions. Owns NO notification logic.",
        "boundaries": "Knows nothing about channels, templates, or customer contact preferences. Its only contract with the notification system is the shape of the domain event."
      },
      {
        "name": "Event Bus (Managed Queue)",
        "responsibility": "Durably stores domain events and guarantees at-least-once delivery to consumers. Provides retry, dead-letter queue (DLQ), and backpressure.",
        "boundaries": "Pure infrastructure — no business logic. Treats events as opaque payloads. SQS, Google Cloud Tasks, or CloudAMQP are appropriate managed options."
      },
      {
        "name": "Notification Router",
        "responsibility": "Consumes domain events, resolves customer contact preferences, selects applicable channels, renders message templates, and fans out dispatch commands — one per channel.",
        "boundaries": "Owns channel selection logic and template rendering. Does NOT call external providers directly — delegates to channel dispatchers."
      },
      {
        "name": "Channel Dispatchers (Email, SMS, future Push/WhatsApp)",
        "responsibility": "Each dispatcher is a thin adapter that calls one external provider API (SendGrid, Twilio, etc.) and reports success/failure.",
        "boundaries": "One dispatcher per channel. Stateless. Implements a common Dispatcher interface. Adding a new channel = deploying a new dispatcher + registering it with the router."
      },
      {
        "name": "Dead-Letter Queue + Alert",
        "responsibility": "Captures events that exhaust all retries. Triggers an alert to the engineering team for manual investigation.",
        "boundaries": "Terminal failure path only — not part of the happy path."
      }
    ],
    "interfaces": [
      {
        "from": "Delivery Service",
        "to": "Event Bus",
        "contract": "Publishes DeliveryStatusChanged event: { eventId, deliveryId, customerId, newStatus, timestamp, metadata }",
        "coupling_type": "loose — fire-and-forget publish, no awareness of consumers"
      },
      {
        "from": "Event Bus",
        "to": "Notification Router",
        "contract": "At-least-once delivery of DeliveryStatusChanged events with visibility timeout and retry policy",
        "coupling_type": "loose — queue-mediated, consumer pulls at own pace"
      },
      {
        "from": "Notification Router",
        "to": "Channel Dispatchers",
        "contract": "Dispatcher interface: dispatch(recipient, renderedMessage) → Success | TransientFailure | PermanentFailure",
        "coupling_type": "abstract coupling — router depends on interface, not concrete implementations"
      },
      {
        "from": "Channel Dispatchers",
        "to": "External Providers (SendGrid, Twilio)",
        "contract": "Provider-specific REST API calls, encapsulated behind the Dispatcher interface",
        "coupling_type": "tight but isolated — each adapter tightly couples to one provider, but the adapter boundary prevents leakage"
      },
      {
        "from": "Event Bus",
        "to": "Dead-Letter Queue",
        "contract": "Events that fail after max retries are moved to DLQ automatically by queue configuration",
        "coupling_type": "infrastructure coupling — configured at the queue level, no application code"
      }
    ],
    "data_flow": "Package status changes in Delivery Service → DeliveryStatusChanged event published to managed queue → Notification Router consumes event, looks up customer preferences, renders templates → fans out to applicable Channel Dispatchers → each dispatcher calls external provider → on transient failure, message returns to queue for retry → on permanent failure after max retries, message lands in DLQ and alert fires.",
    "patterns_used": [
      {
        "pattern": "Domain Events",
        "rationale": "DeliveryStatusChanged is a natural domain event. Publishing it decouples the delivery bounded context from all downstream concerns. The delivery service does not need to know what happens when a status changes — it just announces the fact."
      },
      {
        "pattern": "Competing Consumers (Worker Pool)",
        "rationale": "Notification Router instances pull from the queue independently. This provides horizontal scalability if volume grows, and graceful degradation if a worker dies — the message simply becomes visible again after the visibility timeout."
      },
      {
        "pattern": "Strategy Pattern (Channel Dispatchers)",
        "rationale": "Each channel implements a common Dispatcher interface. The router selects and invokes the appropriate strategy based on customer preferences. Adding WhatsApp or push notifications means adding a new Strategy implementation — zero changes to existing code."
      },
      {
        "pattern": "Dead-Letter Queue",
        "rationale": "Satisfies the hard reliability requirement. No notification is silently dropped. Failed messages are captured for investigation and potential replay."
      },
      {
        "pattern": "Idempotent Consumer",
        "rationale": "At-least-once delivery means duplicates are possible. Each dispatcher must be idempotent — using eventId + channel as a deduplication key — to prevent sending the same SMS twice."
      }
    ]
  },

  "domain_model": {
    "bounded_contexts": [
      {
        "name": "Delivery Tracking",
        "classification": "core",
        "aggregates": ["Delivery (root: deliveryId, tracks status lifecycle, publishes DeliveryStatusChanged)"]
      },
      {
        "name": "Customer Notifications",
        "classification": "supporting",
        "aggregates": ["NotificationPreference (root: customerId, stores channel preferences and contact details)", "NotificationLog (root: notificationId, tracks dispatch attempts and outcomes for auditability)"]
      }
    ],
    "context_map": [
      {
        "upstream": "Delivery Tracking",
        "downstream": "Customer Notifications",
        "relationship": "Customer-Supplier via Domain Events — Delivery Tracking publishes events without knowledge of consumers. Customer Notifications conforms to the event schema but is otherwise autonomous."
      }
    ]
  },

  "trade_offs": [
    {
      "decision": "Option B (event-driven) over Option A (synchronous REST)",
      "gains": "Decoupled delivery service — adding/removing channels requires zero changes to delivery code. Retry is handled by queue infrastructure, not application retry loops. Delivery service latency is unaffected by slow provider APIs. Partial failure is graceful — one channel failing doesn't block others.",
      "sacrifices": "Adds a managed queue dependency. Slightly more complex deployment topology (delivery service + queue + worker). Debugging requires tracing across async boundaries instead of reading a single call stack. Small learning curve for the team on queue semantics (visibility timeout, DLQ configuration).",
      "alternatives_considered": [
        "Option A (synchronous REST): Simpler initial implementation but creates tight coupling. Retry must be hand-coded with circuit breakers. Adding a new channel means modifying the delivery service. A slow or failing provider blocks the delivery status update. Rejected because it violates the reliability requirement and makes extensibility expensive.",
        "Hybrid: synchronous for email, async for others. Rejected because it creates two code paths with different failure semantics — unnecessarily complex for a small team.",
        "Full event-sourcing with Kafka. Rejected as overkill — the team cannot maintain Kafka. A managed SQS/Cloud Tasks queue provides sufficient guarantees with near-zero ops burden."
      ]
    },
    {
      "decision": "Managed queue over self-hosted broker",
      "gains": "Zero infrastructure maintenance for the 3-person team. Built-in retry, DLQ, monitoring, and scaling. SQS costs pennies at courier-company scale.",
      "sacrifices": "Vendor lock-in to a specific cloud provider's queue. Less control over queue internals.",
      "alternatives_considered": [
        "Self-hosted RabbitMQ: more control but requires ops expertise the team does not have."
      ]
    },
    {
      "decision": "Idempotent consumers over exactly-once processing",
      "gains": "Simple and robust — at-least-once delivery with application-level dedup is the standard pattern for managed queues. No need for distributed transactions.",
      "sacrifices": "Requires maintaining a deduplication store (can be a simple DB table or Redis set with TTL). Adds a small amount of per-message overhead.",
      "alternatives_considered": [
        "Exactly-once via FIFO queues: adds ordering constraints and reduces throughput. Unnecessary given the 5-minute latency tolerance."
      ]
    }
  ],

  "flexibility_points": [
    {
      "area": "Channel Dispatchers",
      "evolution_path": "New channels (push, WhatsApp, in-app) are added by implementing the Dispatcher interface and registering with the router. No changes to delivery service, queue, or existing dispatchers."
    },
    {
      "area": "Message Templates",
      "evolution_path": "Templates are owned by the Notification Router. Changing wording, adding localization, or personalizing messages is isolated to this component."
    },
    {
      "area": "Notification Routing Rules",
      "evolution_path": "Customer preferences and channel selection logic live in the Notification Router. Business rules like 'only SMS for out-for-delivery, email for everything else' are easily added without touching other components."
    },
    {
      "area": "Provider Swapping",
      "evolution_path": "Switching from SendGrid to Mailgun means replacing one dispatcher implementation. The router and all other dispatchers are untouched."
    }
  ],

  "rigidity_points": [
    {
      "area": "Domain Event Schema",
      "reason": "DeliveryStatusChanged is the contract between Delivery Tracking and Customer Notifications. Changing this schema requires coordinated updates. Use schema versioning from day one (include a 'version' field in the event)."
    },
    {
      "area": "Queue Infrastructure Choice",
      "reason": "Once the team builds on SQS (or equivalent), switching to a different queue technology requires reworking publish/consume code. Acceptable trade-off given the operational benefits."
    },
    {
      "area": "At-Least-Once Semantics",
      "reason": "The entire design assumes idempotent consumers. Any new consumer added to this system MUST handle duplicates. This is a design invariant, not optional."
    }
  ],

  "risks": [
    {
      "risk": "Duplicate notifications sent to customers due to at-least-once delivery without proper deduplication",
      "severity": "high",
      "mitigation": "Implement idempotency check in each dispatcher using eventId + channel as dedup key. Store processed event IDs in a table with TTL-based cleanup. This MUST be in place before go-live."
    },
    {
      "risk": "Poison messages — a malformed event that crashes the worker on every retry, blocking the queue",
      "severity": "high",
      "mitigation": "Configure max retry count (e.g., 3 attempts with exponential backoff) and DLQ. Add schema validation as the first step in the Notification Router — reject malformed events to DLQ immediately."
    },
    {
      "risk": "Silent DLQ growth — messages land in DLQ but nobody notices",
      "severity": "medium",
      "mitigation": "Set up a CloudWatch alarm (or equivalent) on DLQ depth > 0. Route to PagerDuty or Slack. Assign DLQ review as a weekly operational task."
