    "level": 92,
    "high_confidence_areas": [
      "Option B (event-driven) is the correct choice given the stated constraints — this is a textbook fit",
      "Managed queue over self-hosted broker for a 3-person team",
      "Strategy pattern for channel dispatchers enabling zero-modification extensibility",
      "Idempotency requirement and DLQ-based reliability model"
    ],
    "low_confidence_areas": [
      "Specific cloud provider choice (SQS vs Cloud Tasks vs CloudAMQP) — depends on the team's existing cloud footprint, which was not specified",
      "Exact retry policy parameters (count, backoff intervals) — these should be tuned based on provider SLAs and observed failure rates"
    ],
    "assumptions": [
      "The team is already on or willing to adopt a major cloud provider (AWS, GCP, or Azure) for managed queue services",
      "Notification volume is moderate (thousands to low tens-of-thousands per day) — consistent with a courier company",
      "Customer contact preferences (email, phone number, channel opt-ins) are stored somewhere accessible to the notification system",
      "The delivery service is a single application, not already a distributed microservices architecture"
    ]
  }
}

